mapper.select:
select * from batch.batch_day_replay_session
where tenant_id = #{tenantId}
  and calendar_code = #{calendarCode}
  and biz_date = #{bizDate}
  and status in ('PENDING_APPROVAL', 'RUNNING')
limit 1

